MAGIC = b"GSS1"
VERSION = 1

TYPE_STATUS_QUERY = 0x01
TYPE_STATUS_RESPONSE = 0x81
TYPE_ERROR_RESPONSE = 0xFF

FLAG_COMPRESSED = 0x01
FLAG_FRAGMENTED = 0x02

DEFAULT_MTU = 1200
HEADER_FMT = "!4sBBBBIHHHH"
HEADER_SIZE = struct.calcsize(HEADER_FMT)
# Fields:
# magic(4), version(1), msg_type(1), flags(1), reserved(1),
# request_id(u32),
# frag_index(u16), frag_count(u16),
# payload_len(u16), total_len(u16)

